"use client";
import { useEffect, useState } from "react";

export default function Home() {
  const [apiStatus, setApiStatus] = useState("Connecting...");
  const [syncStatus, setSyncStatus] = useState<Record<string, unknown> | null>(null);

  useEffect(() => {
    const apiUrl = process.env.NEXT_PUBLIC_ZAP_CLAW_URL || "http://localhost:3001";
    fetch(`${apiUrl}/api/sync/pull?deviceId=local-dev-1&channel=web`)
      .then((res) => res.json())
      .then((data) => {
        if (data.events || data.newCursor) {
          setApiStatus(`🟢 ONLINE (${apiUrl})`);
          setSyncStatus(data);
        } else {
          setApiStatus("🟡 WARNING: Invalid Payload");
        }
      })
      .catch(() => {
        setApiStatus(`🔴 OFFLINE (Ensure ZAP Claw is running at ${apiUrl})`);
      });
  }, []);

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-black p-8 font-mono text-zinc-100 selection:bg-purple-900 selection:text-white">
      <main className="flex w-full max-w-2xl flex-col gap-8 rounded-lg border border-zinc-800 bg-zinc-950 p-10 shadow-2xl">
        <header className="border-b border-zinc-900 pb-5">
          <h1 className="text-3xl font-bold tracking-tighter text-white">OLYMPUS HUB</h1>
          <p className="mt-2 text-sm text-zinc-400">Phase 0: 12-User Local-First Prototype</p>
        </header>

        <section className="flex flex-col gap-4">
          <div className="flex items-center justify-between rounded-md border border-zinc-800 bg-zinc-900 px-4 py-3">
            <span className="font-semibold text-zinc-300">ZAP Claw (API Gateway)</span>
            <span className="text-sm font-medium tracking-wide">{apiStatus}</span>
          </div>

          {syncStatus && (
            <div className="rounded-md border border-green-900/30 bg-green-950/20 p-4">
              <span className="mb-2 block text-xs font-semibold text-green-500 uppercase tracking-wider">Sync Payload Received</span>
              <pre className="text-xs text-green-400 overflow-x-auto">
                {JSON.stringify(syncStatus, null, 2)}
              </pre>
            </div>
          )}

          <div className="flex items-center justify-between rounded-md border border-zinc-800 bg-zinc-900 px-4 py-3">
            <span className="font-semibold text-zinc-300">ZAP Design Engine</span>
            <a
              href="http://localhost:3002"
              target="_blank"
              rel="noopener noreferrer"
              className="text-sm font-medium tracking-wide text-blue-400 hover:text-blue-300 underline underline-offset-4 transition-colors"
            >
              Open Workspace (Port 3002) ↗
            </a>
          </div>
        </section>

        <footer className="mt-4 border-t border-zinc-900 pt-5 text-center text-xs text-zinc-600">
          ZAP Inc. Infrastructure • Olympus Monorepo Navigation
        </footer>
      </main>
    </div>
  );
}
